from agent import *from models.products import *def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request('http://www.zeneszmagazin.hu/'), process_frontpage, dict())def process_frontpage(data, context, session):    cats = data.xpath("//a[@class='g-menu-item-container' and contains(@href, 'https://www.zeneszmagazin.hu/technika/')]")    for cat in cats:        name = cat.xpath(".//text()").string(multiple=True)        url = cat.xpath("@href").string()        session.queue(Request(url), process_revlist, dict(cat=name))def process_revlist(data, context, session):    revs = data.xpath("//div[@class='page-header']/h2/a")    for rev in revs:        name = rev.xpath("text()").string(multiple=True)        url = rev.xpath("@href").string()        session.queue(Request(url), process_review, dict(context, name=name, url=url))    next_url = data.xpath("//li[@class='pagination-next']/a/@href").string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.name = context['name']    product.url = context['url']    product.ssid = context['url'].split('/')[-1].split('-')[0]    product.category = context['cat']    review = Review()    review.type = 'pro'    review.title = context['name']    review.url = context['url']    review.ssid = product.ssid    review.date = data.xpath("//time/@datetime").string().split('T')[0]    author = data.xpath("//dd[@itemprop='author']/span/text()").string()    if author:        review.authors.append(Person(name=author, ssid=author))    summary = data.xpath("//div[@itemprop='articleBody']/p[1]/strong/text()").string(multiple=True)    if summary:        review.add_property(type='summary', value=summary)    conclusion = data.xpath("//div[@itemprop='articleBody']/p[contains(., 'Összegzés')]/following-sibling::p[1]//text()").string(multiple=True)    if conclusion:        review.add_property(type='conclusion', value=conclusion)    excerpt = data.xpath("//div[@itemprop='articleBody']/p[normalize-space(text())]//text()").string(multiple=True)    if excerpt:        if summary:            excerpt = excerpt.replace(summary.strip(), '')        if conclusion:            excerpt = excerpt.replace(conclusion.strip(), '')        excerpt = excerpt.strip()        if excerpt:            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)            session.emit(product)